  4158→  | { type: 'SELECT_TRAIN'; trainId: string };
  4159→
  4160→const fleetMachine = createMachine<FleetState, FleetEvent>({
  4161→  initial: 'idle',
  4162→  context: {
  4163→    trains: [],
  4164→    depots: [],
  4165→    selectedTrainId: null,
  4166→    loading: false,
  4167→    error: null,
  4168→  },
  4169→  states: {
