  4186→          actions: ['setError'],
  4187→        },
  4188→      },
  4189→    },
  4190→    error: {
  4191→      on: {
  4192→        FETCH_TRAINS: {
  4193→          target: 'loading',
  4194→          actions: ['setLoading', 'clearError'],
  4195→        },
  4196→      },
  4197→    },
