  4247→```typescript
  4248→// lib/api.ts
  4249→const API_BASE = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:4000/api';
  4250→
  4251→interface ApiResponse<T> {
  4252→  data: T;
  4253→  meta?: {
  4254→    total?: number;
  4255→    page?: number;
  4256→  };
  4257→}
  4258→
  4259→interface ApiError {
  4260→  error: string;
  4261→  code: string;
  4262→  details?: Record<string, unknown>;
  4263→}
  4264→
  4265→async function request<T>(
  4266→  endpoint: string,
  4267→  options: RequestInit = {}
  4268→): Promise<T> {
  4269→  const url = `${API_BASE}${endpoint}`;
  4270→
  4271→  const response = await fetch(url, {
  4272→    ...options,
  4273→    headers: {
  4274→      'Content-Type': 'application/json',
  4275→      ...options.headers,
  4276→    },
  4277→  });
  4278→
  4279→  if (!response.ok) {
  4280→    const error: ApiError = await response.json();
  4281→    throw new Error(error.error || 'API Error');
  4282→  }
  4283→
  4284→  const result: ApiResponse<T> = await response.json();
  4285→  return result.data;
  4286→}
